#!/usr/bin/env bash
# generate-manifest.sh — Re-render manifests for ok2-rmf from cluster-config.yaml
# Generated by render.py
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
ROOT_DIR="$(cd "${SCRIPT_DIR}/../.." && pwd)"

echo "Re-rendering manifests for cluster: ok2-rmf"
python3 "${ROOT_DIR}/render.py" render --cluster "ok2-rmf"
echo "Done."
